import React from "react";

function Merch(props) {
  const merchandise = props.merchandise;

  if (!merchandise) {
    return null;
  }

  const { _id, name, price, description, stock, category } = merchandise;

  return (
    <div>
      <h2>Merchandise</h2>
      <p>ID: {_id}</p>
      <p>Name: {name}</p>
      <p>Price: LKR. {price}</p>
      <p>Description: {description}</p>
      <p>Stock: {stock}</p>
      <p>Category: {category}</p>
      <button>Edit</button>
      <button>Delete</button>
    </div>
  );
 }

export default Merch;
